  if (item.textContent.trim() === 'One') oneElement = item;
  if (item.textContent.trim() === 'Three') threeElement = item;
});

// 使用拖拽API进行拖拽操作
if (oneElement && threeElement) {
  // 获取Three元素的位置
  const threeRect = threeElement.getBoundingClientRect();

  // 创建拖拽事件
  function createDragEvent(type, element, clientX, clientY) {
    const event = new DragEvent(type, {
      bubbles: true,
      cancelable: true,
      clientX: clientX,
      clientY: clientY
    });
    return event;
  }

  // 开始拖拽One
  oneElement.dispatchEvent(createDragEvent('dragstart', oneElement, oneElement.getBoundingClientRect().left, oneElement.getBoundingClientRect().top));

  // 在Three下方结束拖拽
  const dropY = threeRect.bottom + 10;
  threeElement.dispatchEvent(createDragEvent('dragover', threeElement, threeRect.left, dropY));
  threeElement.dispatchEvent(createDragEvent('drop', threeElement, threeRect.left, dropY));
  oneElement.dispatchEvent(createDragEvent('dragend', oneElement, threeRect.left, dropY));

  return 'Drag and drop completed';
} else {
  return 'Elements not found';
}"})
